parameters.jsCode:
// Pega o primeiro item
const item = items[0];
const outputUnico = item.json.output || '';

// Split por separador explícito ou envia como mensagem única
let mensagensIndividuais;
if (outputUnico.includes('---SPLIT---')) {
  mensagensIndividuais = outputUnico.split('---SPLIT---').map(m => m.trim()).filter(msg => msg !== '');
} else {
  mensagensIndividuais = [outputUnico.trim()].filter(msg => msg !== '');
}

// Limite de segurança: máximo 10 mensagens
if (mensagensIndividuais.length > 10) {
  mensagensIndividuais = mensagensIndividuais.slice(0, 10);
}

// Fallback se output vazio
if (mensagensIndividuais.length === 0) {
  mensagensIndividuais = ['Ops, tive uma instabilidade aqui. Pode repetir sua mensagem?'];
}

const novosItens = mensagensIndividuais.map(mensagem => {
  return {
    json: {
      ...item.json,
      output: mensagem
    }
  };
});

return novosItens;

// Pega os dados que acabaram de vir do nó anterior (Limpar Buffer1 ou Redis2)
const input = items[0].json;
const mensagens = input.mensagens;

if (!mensagens || (Array.isArray(mensagens) && mensagens.length === 0)) {
  return [{ json: { full_message: null } }];
}

let messagesArray = mensagens;

if (typeof mensagens === 'string') {
  try {
    messagesArray = JSON.parse(mensagens);
  } catch (e) {
    messagesArray = [mensagens];
  }
}

const fullMessage = Array.isArray(messagesArray) ? messagesArray.join('\n') : String(messagesArray);

return [{
  json: {
    full_message: fullMessage,
    // Em vez de buscar do NORM, vamos tentar pegar do input se ele existir
    // ou deixar para o próximo nó tratar a falta do número
    number_clean: input.number_clean || null 
  }
}];

// Percorre todos os itens da lista (mesmo que seja só 1)
return items.map(i => {
  let msgs = i.json.mensagens;

  // Se for texto (string), tenta converter
  if (typeof msgs === 'string') {
    try {
      // Tenta fazer o parse do JSON (ex: "['oi', 'tudo bem']")
      msgs = JSON.parse(msgs);
    } catch (e) {
      // Se der erro no parse (ex: texto puro "intervencao_humana"), 
      // transforma em um array com esse único texto.
      msgs = [msgs];
    }
  }

  // Garante que se veio null ou undefined, vira array vazio
  if (!msgs) {
    msgs = [];
  }

  // Atualiza o item e retorna
  i.json.mensagens = msgs;
  return i;
});

const mime =
  $('Webhook').first().json.body?.conteudo_buffer?.mimetype
  || 'image/jpeg';

let ext = (mime.split('/')[1] || 'jpg').toLowerCase();
if (ext === 'jpeg') ext = 'jpg';

for (const item of items) {
  if (item.binary?.file) {
    item.binary.file.fileName = `imagem.${ext}`;
    item.binary.file.mimeType = mime;
    item.binary.file.fileExtension = ext;
  }
}
return items;

for (const item of items) {
  if (item.binary?.file) {
    item.binary.file.fileName = 'arquivo.pdf';
    item.binary.file.mimeType = 'application/pdf';
    item.binary.file.fileExtension = 'pdf';
  }
}
return items;

for (const item of items) {
  if (item.binary?.file) {
    item.binary.file.fileName = 'audio.ogg';
    item.binary.file.mimeType = 'audio/ogg';
    item.binary.file.fileExtension = 'ogg';
  }
}
return items;

